const std = @import("std");

pub const BankInfo = struct {
    blz: [8]u8,
    bic: [11]u8,
    bic_len: u8,
    name: [64]u8,
    name_len: u8,
    url: [128]u8,
    url_len: u8,

    pub fn nameSlice(self: *const BankInfo) []const u8 {
        return self.name[0..self.name_len];
    }

    pub fn urlSlice(self: *const BankInfo) []const u8 {
        return self.url[0..self.url_len];
    }

    pub fn blzSlice(self: *const BankInfo) []const u8 {
        return &self.blz;
    }

    pub fn bicSlice(self: *const BankInfo) []const u8 {
        return self.bic[0..self.bic_len];
    }
};

fn makeBank(blz: *const [8]u8, bic: []const u8, name: []const u8, url: []const u8) BankInfo {
    var b: BankInfo = .{
        .blz = blz.*,
        .bic = undefined,
        .bic_len = @intCast(bic.len),
        .name = undefined,
        .name_len = @intCast(name.len),
        .url = undefined,
        .url_len = @intCast(url.len),
    };
    @memset(&b.bic, 0);
    @memset(&b.name, 0);
    @memset(&b.url, 0);
    if (bic.len > 0) @memcpy(b.bic[0..bic.len], bic);
    @memcpy(b.name[0..name.len], name);
    @memcpy(b.url[0..url.len], url);
    return b;
}

